#include <bits/stdc++.h>
using namespace std;
struct Dinic{struct E{int to,cap,rev;};int N;vector<vector<E>>G;vector<int>L,it;Dinic(int n):N(n),G(n+1){};void add(int u,int v,int c){E a{v,c,(int)G[v].size()},b{u,0,(int)G[u].size()};G[u].push_back(a);G[v].push_back(b);}bool bfs(int s,int t){L.assign(N+1,-1);queue<int>q;L[s]=0;q.push(s);while(!q.empty()){int u=q.front();q.pop();for(auto &e:G[u])if(e.cap>0&&L[e.to]<0){L[e.to]=L[u]+1;q.push(e.to);}}return L[t]>=0;}int dfs(int u,int t,int f){if(!f||u==t)return f;for(int &i=it[u];i<(int)G[u].size();++i){auto &e=G[u][i];if(e.cap>0&&L[e.to]==L[u]+1){int r=dfs(e.to,t,min(f,e.cap));if(r){e.cap-=r;G[e.to][e.rev].cap+=r;return r;}}}return 0;}long long flow(int s,int t){long long F=0;const int INF=1e9;while(bfs(s,t)){it.assign(N+1,0);while(int f=dfs(s,t,INF))F+=f;}return F;}};
int main(){int n,m;if(!(cin>>n>>m))return 0;vector<pair<int,int>> es(m);for(int i=0;i<m;++i)cin>>es[i].first>>es[i].second; long long sum=0; for(int a=1;a<=n;a++)for(int b=a+1;b<=n;b++){Dinic d(n);for(auto &e:es){d.add(e.first,e.second,1);d.add(e.second,e.first,1);}sum+=d.flow(a,b);}cout<<sum<<n;}
